  return (
    <div className='hero'>
        <h1>Best Collection of Products</h1>
        <p>Lorem ipsum dolor, sit amet consectetur adipisicing elit. Sed reprehenderit facere mag<br></br>nam, esse consequatur vero cumque explicabo. Est perferendis aperiam earum sunt ad seq<br></br>ui, culpa ducimus error officiis placeat cupiditate.</p>
        <Button variant="primary">Shop Now</Button>
        <Image src="//Assets/hero_image.png" rounded />
        </div>
  )
}

export default Hero
